mapper.select:
SELECT e.id, e.expense_type AS expenseType, e.amount, e.expense_date AS expenseDate, e.description, e.receipt_path AS receiptPath, e.registered_by AS registeredBy, e.status, emp.name AS registeredByName, e.created_at AS createdAt FROM expenses e LEFT JOIN employees emp ON e.registered_by = emp.id
AND e.status = 1
AND e.expense_type = #{expenseType}
AND e.expense_date >= #{dateFrom}
AND e.expense_date <= #{dateTo}
AND e.description LIKE CONCAT('%', #{keyword}, '%')
ORDER BY e.created_at DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM expenses e

    AND e.status = 1

        AND e.expense_type = #{expenseType}


        AND e.expense_date >= #{dateFrom}


        AND e.expense_date <= #{dateTo}


        AND e.description LIKE CONCAT('%', #{keyword}, '%')

mapper.update:
UPDATE expenses
SET receipt_path = #{receiptPath}
WHERE id = #{id}

mapper.select:
SELECT p.id, p.employee_id AS employeeId, p.pay_year AS payYear, p.pay_month AS payMonth, p.work_hours AS workHours, p.base_pay AS basePay, p.deduction, p.net_pay AS netPay, p.paid_at AS paidAt, p.note, p.created_at AS createdAt, p.pay_type AS payType, e.name AS employeeName, e.emp_num AS employeeNo FROM payrolls p LEFT JOIN employees e ON p.employee_id = e.id
AND p.pay_year = #{payYear}
AND p.pay_month = #{payMonth}
AND e.name LIKE CONCAT('%', #{keyword}, '%')
ORDER BY p.pay_year DESC, p.pay_month DESC, p.id DESC LIMIT #{size} OFFSET #{offset}

SELECT COUNT(*)
FROM payrolls p
LEFT JOIN employees e ON p.employee_id = e.id


        AND p.pay_year = #{payYear}


        AND p.pay_month = #{payMonth}


        AND e.name LIKE CONCAT('%', #{keyword}, '%')

